-- Migration 012f: Implementation Plans — Batch F (IDs 86-95)
-- ─────────────────────────────────────────────────────────────────────────────────────
BEGIN;

-- ── ID 86: BELA Act Implementation: Admissions, Language Policy, and Grade R ─────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    86,
    'The Basic Education Laws Amendment (BELA) Act, signed September 2024, requires the DBE and nine provincial education departments to operationalise three principal reforms: DBE oversight of school admissions policy to reduce discriminatory exclusion; Head of Department approval for SGB language policy decisions to promote multilingualism; and the introduction of compulsory Grade R. The MEC must issue provincial regulations within 12 months of the Act''s commencement. Implementation requires coordinated gazette notices, provincial capacity support, and a national communications campaign to manage community expectations, particularly in historically Afrikaans-medium schools in the Western Cape and Gauteng where DA-aligned SGBs have signalled litigation risk. Success is measured by full compliance with the admissions framework across all quintiles by end-2026 and Grade R enrolment reaching 95% of the eligible cohort by 2027.',
    '[{"step":1,"description":"DBE publishes draft commencement regulations under the BELA Act covering admissions policy framework, SGB language policy approval process, and Grade R compulsory attendance requirements; 30-day public comment period","timeline":"Q1 2025","responsible_party":"Department of Basic Education (DBE) / Office of the Director-General"},{"step":2,"description":"DBE and nine provincial education departments (PEDs) convene joint implementation planning sessions; assign provincial BELA Act implementation coordinators; develop provincial gazette notice templates and SGB engagement protocols","timeline":"Q1–Q2 2025","responsible_party":"DBE / Provincial Education Departments (PEDs)"},{"step":3,"description":"Each MEC issues provincial BELA Act implementation regulations within the 12-month statutory window; DBE monitors gazette compliance and flags non-compliant provinces to the Portfolio Committee on Basic Education","timeline":"Q3 2025 (12-month deadline)","responsible_party":"Provincial MECs for Education / DBE"},{"step":4,"description":"DBE commissions a national admissions audit: identify schools with exclusionary admissions criteria (language, religion, academic selection at entry); direct provinces to rectify non-compliant admissions policies using the new HoD approval mechanism","timeline":"Q3–Q4 2025","responsible_party":"DBE / South African Human Rights Commission"},{"step":5,"description":"Grade R rollout acceleration: DBE and PEDs identify schools lacking Grade R classes; deploy additional Grade R practitioners using the Funza Lushaka pipeline and DHET-accredited ECD qualifications; allocate per-learner subsidy increase for Grade R","timeline":"2025–2026 school year","responsible_party":"DBE / DHET / PEDs"},{"step":6,"description":"Establish a BELA Act litigation monitoring unit within DBE''s legal services directorate to track SGB challenges; coordinate with the State Attorney to defend HoD language policy decisions; brief Portfolio Committee quarterly on litigation outcomes","timeline":"Ongoing from Q2 2025","responsible_party":"DBE Legal Services / State Attorney"},{"step":7,"description":"Three-year BELA Act impact review: commission independent assessment of admissions compliance, language policy changes, and Grade R enrolment outcomes; report to Parliament with recommendations for any regulatory adjustments","timeline":"Q4 2027","responsible_party":"DBE / SAHRC / Portfolio Committee on Basic Education"}]',
    '2025–2027 for primary implementation; Grade R universalisation by end-2027',
    'Grade R infrastructure and practitioner costs: R4–6 billion over three years (capital and recurrent); admissions and language policy implementation absorbed within existing DBE/PED operational budgets; legal monitoring unit: R15 million/year',
    'BELA Act (Basic Education Laws Amendment Act, 2024) already signed — no new primary legislation required. MECs must issue provincial regulations under the Act''s commencement provisions. Potential litigation under section 29 (right to education in language of choice) and section 31 (cultural and religious community rights) of the Constitution is anticipated.',
    'Provincial regulations are secondary legislation issued by MECs under the BELA Act — no parliamentary vote required. Each province must gazette its regulations within the 12-month window. DBE can use section 100 constitutional intervention powers if provinces fail to implement. The Grade R subsidy increase requires National Treasury concurrence in the Annual Budget process.',
    'Implementation is constitutionally supported but politically contested. The ANC-led national government and DBE have firm legislative backing. The DA (governing Western Cape) has publicly opposed the SGB language policy approval requirement as an infringement of community rights and may challenge in court. The EFF supports the admissions and multilingualism provisions. Business community (Business Unity SA) backs the Grade R expansion. Broad civil society consensus on the equity rationale for the Act exists, though litigation risk from Afrikaans-medium school associations is real.',
    'New Zealand''s National Curriculum reform (2020–23) navigated similar tensions between centralised standards and local school governance, ultimately using a co-design model with school communities — a precedent DBE could adopt for language policy transitions. Kenya''s 2017 Competency-Based Curriculum introduced compulsory pre-primary (Grade R equivalent) nationally with phased PED capacity building, achieving 92% enrolment within three years. Finland''s pre-primary expansion in the 1990s used ring-fenced per-child grants to municipalities, a funding model relevant to Grade R subsidy design.'
);

-- ── ID 87: ECD Function Shift: Early Childhood Development Migration to DBE ───────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    87,
    'The Constitutional Court ordered the transfer of the Early Childhood Development function from the Department of Social Development (DSD) to the Department of Basic Education (DBE), with a phased migration of approximately 17,000 ECD centres serving 1.1 million children aged 0–4 from 2022 to 2030. The function shift encompasses budget transfers, staff migration, infrastructure norms, and a new ECD registration and quality assurance system. The Auditor-General has flagged slow implementation: as of 2024, fewer than 40% of ECD centres have completed the registration and norms-assessment process, and budget transfers between national and provincial treasuries remain incomplete in four provinces. The programme''s success depends on absorbing the largely informal, community-based ECD sector — typically NGO- and CBO-operated — into a DBE regulatory framework without disrupting service delivery to the country''s most vulnerable children.',
    '[{"step":1,"description":"DBE and DSD jointly finalise the ECD function shift transition plan with province-by-province implementation schedules; National Treasury resolves conditional grant and equitable share allocation adjustments; establish inter-departmental ECD Transfer Steering Committee with monthly reporting to the Director-General cluster","timeline":"Q1–Q2 2025","responsible_party":"DBE / DSD / National Treasury / Provincial Treasuries"},{"step":2,"description":"Complete ECD centre registration drive: deploy provincial ECD registration teams to identify, register, and conduct basic quality assessments of all 17,000 ECD centres not yet in the DBE system; prioritise quintile 1–3 catchment areas; use SACE-approved practitioners as assessors","timeline":"2025–2026","responsible_party":"DBE / PEDs / SACE"},{"step":3,"description":"Develop and gazette DBE ECD Minimum Norms and Standards: covering infrastructure (water, sanitation, indoor/outdoor space per child), practitioner qualifications (NQF Level 4 ECD certificate minimum), and curriculum alignment with the National Curriculum Framework 0–4; phase-in compliance timeline of three years for existing centres","timeline":"Q2–Q3 2025","responsible_party":"DBE / QCTO / DHET"},{"step":4,"description":"Establish a progressive subsidy schedule: all registered ECD centres receive a per-child subsidy from DBE conditional on minimum compliance; increase subsidy from R17/child/day (DSD legacy rate) to R35/child/day by 2027 as the function shift budget is absorbed; National Treasury adjusts provincial equitable share accordingly","timeline":"2025–2027 budget cycles","responsible_party":"DBE / National Treasury / Provincial Treasuries"},{"step":5,"description":"ECD practitioner qualification and training programme: DHET and QCTO accredit short-course pathways to NQF Level 4 ECD qualification; target 50,000 practitioners completing accredited training by 2028 through TVET colleges and distance learning providers","timeline":"2025–2028","responsible_party":"DHET / QCTO / TVET Colleges"},{"step":6,"description":"Infrastructure investment programme: DBE allocates infrastructure grants (ISDG or new ECD-specific grant) to upgrade the worst-performing ECD facilities; target 2,000 centre upgrades per year; prioritise centres serving farm and rural communities","timeline":"2026–2030","responsible_party":"DBE / ASIDI / PEDs"},{"step":7,"description":"Annual Auditor-General reporting: DBE publishes a mandatory annual ECD Function Shift Progress Report covering registration rates, subsidy disbursement, practitioner qualification completion, infrastructure upgrades, and child development outcome data; table in Parliament","timeline":"Annual from Q3 2025","responsible_party":"DBE / Auditor-General of South Africa"}]',
    '2022–2030 (phased Constitutional Court-ordered timeline); core administrative transfer complete by 2026; full quality and subsidy parity by 2030',
    'R12–18 billion total over 2025–2030: subsidy scale-up (R6–8 billion), practitioner training (R2 billion), infrastructure upgrades (R4–6 billion); largely reallocation from DSD to DBE budget lines with National Treasury adjustment to equitable share formula',
    'No new primary legislation required — the Constitutional Court order provides the legal basis. DBE ECD Minimum Norms and Standards require gazette under the Schools Act or a dedicated ECD framework. The ECD Amendment Bill (anticipated 2025) would consolidate the legal framework for the transferred function.',
    'The Constitutional Court order is binding — this is an implementation obligation, not a policy choice. DBE gazettes norms as administrative regulations under existing statutory powers. The ECD Amendment Bill (if tabled in 2025) requires parliamentary passage; NCOP involvement is required as it affects provincial competencies. National Treasury''s equitable share adjustments are made through the Division of Revenue Act each budget cycle.',
    'Cross-party support for ECD investment exists — DA, ANC, EFF all rhetorically endorse early childhood development. The practical challenge is bureaucratic: DSD has been reluctant to relinquish budget and staff, and provinces face simultaneous capacity demands. Civil society (SACE, ELRU, Ilifa Labantwana) has been critical of the slow pace and advocates for accelerated subsidy increases. The Auditor-General''s adverse findings create accountability pressure on DBE to demonstrate progress.',
    'Chile''s Chile Crece Contigo universal ECD programme (2006–present) transferred ECD from welfare to education systems and achieved near-universal coverage of 0–4 year olds within a decade, using a progressive subsidy model. Ethiopia''s O-Class programme integrated pre-primary into the school system using community facilitators with short-course qualifications — directly relevant to South Africa''s community-based ECD sector. The UK''s Sure Start programme (1999–2010) provides both a model for integrated ECD service delivery and cautionary lessons about funding discontinuity.'
);

-- ── ID 88: National Reading and Literacy Crisis Response Programme ────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    88,
    'PIRLS 2021 revealed that 81% of South African Grade 4 learners cannot read for meaning — the worst result among all 57 participating countries. The Early Grade Reading Assessment (EGRA) conducted by DBE confirms systemic failures in phonics instruction, teacher reading pedagogy, and home language literacy support, particularly in rural African Language Medium schools. DBE''s Reading Improvement Plan (2023) and the Early Grade Reading Programme (EGRP) operating in seven provinces represent the current policy response, but are funded at R2 billion against a credible estimate of R15 billion needed for national scale. This programme consolidates existing initiatives under a single National Literacy Response Programme with a dedicated budget line, a structured literacy curriculum (phonics-first), intensive teacher coaching, and a reading materials distribution system targeting every Grade R–3 learner by 2028.',
    '[{"step":1,"description":"DBE commissions a national literacy audit: province-by-province EGRA assessment of Grade 1–3 learners to establish a baseline; identify lowest-performing districts (bottom quintile); publish audit findings as a public accountability tool","timeline":"Q1–Q2 2025","responsible_party":"DBE / UNICEF / USAID EGRA partners"},{"step":2,"description":"Develop and gazette a mandatory Structured Literacy Curriculum for Grades R–3: explicit phonics sequence, phonemic awareness activities, and decodable reader progression in all 11 official home languages; replace the current eclectic reading approach with a research-validated systematic phonics framework","timeline":"Q2–Q3 2025","responsible_party":"DBE Curriculum and Assessment Policy Branch"},{"step":3,"description":"Teacher reading coaching programme: train 15,000 foundation phase coaches (one per 15 classrooms) using the DBE Reading Coaches Manual; integrate coaching into the EGRP provincial structures already operating in 7 provinces; extend to all 9 provinces by end-2025","timeline":"Q3 2025–Q2 2026","responsible_party":"DBE / PEDs / SACE"},{"step":4,"description":"Reading materials procurement and distribution: procure 8 million decodable readers and supplementary literacy materials in all 11 official languages at home language level for Grades R–3; distribute via provincial depots with school-level confirmation of receipt; use National Treasury RT transversal contracts to suppress cost","timeline":"2025–2026 school years","responsible_party":"DBE / National Treasury / Provincial Education Departments"},{"step":5,"description":"Family and community literacy support programme: partner with SABC Education, community radio stations, and NGOs (BookDash, Nal''ibali) to deliver a national parent literacy engagement campaign; distribute 2 million take-home reading packs to Grade R–1 learners in quintile 1–3 schools","timeline":"2025–2026","responsible_party":"DBE / SABC Education / Nal''ibali / BookDash"},{"step":6,"description":"National Literacy Programme dedicated budget line: National Treasury, DBE, and provinces agree a ring-fenced Reading and Literacy Conditional Grant of R3 billion/year for five years (2026–2030), scaling to the R15 billion total investment target; programme managed by DBE with independent outcome evaluation","timeline":"2025 MTEF budget cycle (for 2026 implementation)","responsible_party":"DBE / National Treasury"},{"step":7,"description":"Five-year PIRLS participation and national literacy benchmarking: South Africa participates in PIRLS 2026 with a provincially disaggregated sample; independently commission annual EGRA monitoring to track Grade 3 reading fluency against a target of reducing the non-reader proportion from 81% to below 40% by 2030","timeline":"Annual monitoring; PIRLS 2026 participation","responsible_party":"DBE / HSRC / IEA PIRLS"}]',
    '2025–2030 for national scale implementation; PIRLS 2026 provides first independent benchmark of progress',
    'R15 billion over five years for full national scale: teacher coaching (R2 billion), materials (R3 billion), family literacy (R500 million), programme management and evaluation (R500 million); currently funded at R2 billion — a R13 billion gap requiring National Treasury commitment to a dedicated conditional grant',
    'No new primary legislation required. The National Curriculum and Assessment Policy Statements (CAPS) can be revised by the Minister under the Schools Act without parliamentary vote. A dedicated Literacy Conditional Grant requires inclusion in the Division of Revenue Act (annual budget legislation).',
    'DBE Ministerial approval for a revised CAPS phonics sequence is an administrative decision. The conditional grant requires National Treasury support and inclusion in the annual Division of Revenue Bill. This is technically non-controversial — no party opposes reading improvement — but competes for budget with infrastructure and ECD commitments.',
    'Cross-party political consensus that the PIRLS 2021 result is a national crisis. The ANC, DA, and EFF have all called for urgent literacy intervention. The main implementation risk is not political opposition but bureaucratic inertia and provincial capacity. USAID EGRA and UNICEF have offered technical assistance. Teacher unions (SADTU) are broadly supportive of reading coaching as a professional development benefit rather than a performance management threat.',
    'The Philippines'' Every Child A Reader Program (ECARP, 2001–present) achieved a reduction in non-readers from 52% to 18% over 15 years through systematic phonics instruction and reading coaches in all elementary schools. Peru''s En Positivo reading programme used structured literacy with decodable readers and reduced Grade 2 non-readers from 65% to 44% in four years. Ethiopia''s USAID-funded Early Grade Reading program achieved an 80% improvement in reading fluency scores in two years using mother-tongue structured literacy — directly relevant to SA''s African Language Medium schools.'
);

-- ── ID 89: STEM Teacher Development and Retention Programme ──────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    89,
    'South Africa faces a structural STEM teacher deficit: universities produce approximately 2,000 qualified mathematics teachers per year against DHET''s estimated need of 8,000. The Funza Lushaka bursary scheme trains 14,000 teachers annually across subjects but suffers a 40% attrition rate within five years, particularly in rural and township schools. Grade 12 mathematics and physical science pass rates — 58% and 70% respectively in 2024 — mask catastrophic throughput: fewer than 30% of Grade 8 cohorts reach Grade 12 mathematics. The programme addresses the supply-side deficit through a STEM teacher bursary expansion, improved rural posting incentives, a subject specialist coaching network, and a DHET-DBE compact on teacher deployment to high-need schools.',
    '[{"step":1,"description":"DHET and DBE jointly publish a STEM Teacher Demand and Supply Audit: province-by-province mapping of vacant mathematics and science posts, Funza Lushaka placement rates, retention data by rural/urban/township category, and university teacher education pipeline projections to 2030","timeline":"Q1–Q2 2025","responsible_party":"DHET / DBE / SACE"},{"step":2,"description":"Expand Funza Lushaka STEM-focused bursaries: increase annual STEM bursary awards from 2,000 to 5,000 by 2027; introduce a STEM-specific bursary category with enhanced monthly stipend (R1,500 above standard Funza Lushaka rate) and guaranteed rural deployment bonus of R5,000/month for first three years of posting","timeline":"2025 academic year intake","responsible_party":"DHET / NSFAS"},{"step":3,"description":"Rural STEM teacher retention package: introduce a Rural STEM Teacher Allowance (R3,000–5,000/month) for qualified mathematics and science teachers posted to quintile 1–2 schools; provide subsidised accommodation in rural school hostels; allow accelerated salary progression after three consecutive years of rural service","timeline":"Q2 2025 (budget allocation for 2026)","responsible_party":"DBE / DPSA / National Treasury"},{"step":4,"description":"STEM subject specialist coaching network: appoint 500 Mathematics and Science District Subject Specialists (one per 20 STEM teachers in underperforming districts); train specialists through SACE-accredited subject-specific professional development programmes; integrate with DBE''s district-based support model","timeline":"2025–2026","responsible_party":"DBE / PEDs / SACE / Universities"},{"step":5,"description":"DHET-DBE STEM Teacher Compact: formalise a binding agreement on Funza Lushaka graduate deployment to high-need schools; SACE to track placement compliance; DBE PEDs to provide orientation support and mentorship for newly posted STEM teachers in first year of service","timeline":"Q2 2025","responsible_party":"DHET / DBE / SACE"},{"step":6,"description":"In-service STEM teacher upskilling: universities (through DHET funding) offer accredited Advanced Diplomas in Mathematics or Physical Science Teaching for under-qualified in-service teachers; target 3,000 teachers completing upskilling qualifications by 2028 using blended learning and school-release time agreements","timeline":"2025–2028","responsible_party":"DHET / Universities / SACE"},{"step":7,"description":"Annual STEM teacher metrics report: DBE and DHET publish joint annual data on STEM teacher vacancies, Funza Lushaka placements, retention rates, Grade 12 mathematics and science pass rates by district, and subject specialist coaching reach; table before Portfolio Committees on Education","timeline":"Annual from Q3 2025","responsible_party":"DBE / DHET / SACE"}]',
    '2025–2030 to reach annual production of 6,000 qualified STEM teachers and reduce rural vacancy rate below 5%',
    'Funza Lushaka STEM expansion: R1.2 billion/year (5,000 bursaries at ~R240,000 each including stipend top-up); rural allowance: R600 million/year; subject specialist coaches: R300 million/year; in-service upskilling: R500 million over four years; total incremental cost approximately R2.5 billion/year above baseline',
    'No new primary legislation required. Funza Lushaka is a conditional grant administered under DHET''s budget; expansion requires annual DORA adjustment. Rural allowance requires DPSA amendment to the Public Service Regulations on remuneration. SACE Act may require amendment to formalise subject specialist accreditation pathways.',
    'Funza Lushaka expansion is an administrative budget decision implemented through DHET''s conditional grant framework and DORA schedules. Rural allowance requires DPSA concurrence and National Treasury cost certification. The DHET-DBE Compact is an inter-departmental agreement — no legislation required. SACE Act amendments (if needed) require parliamentary passage.',
    'Cross-party support for STEM education investment is strong. Business (BUSA, NSTF) and civil society (Equal Education, Section27) all advocate for teacher quality improvement. SADTU is supportive of rural allowances and professional development but may resist performance-linked components. The challenge is National Treasury fiscal space — the rural allowance and bursary expansion cost is substantial and competes with other education priorities.',
    'Singapore''s National Institute of Education teacher pipeline model — combining competitive bursaries, guaranteed placement, mentored induction, and structured career progression — is the global benchmark for STEM teacher quality. Finland''s teacher education system (master''s degree entry, high social status, competitive selection) provides a long-term structural aspiration. Kenya''s TSC (Teachers Service Commission) rural hardship allowance reduced rural teacher vacancy rates from 22% to 8% within five years — directly applicable to South Africa''s rural posting problem.'
);

-- ── ID 90: School Infrastructure Acceleration: Eliminating Inappropriate Structures ──
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    90,
    'The Accelerated Schools Infrastructure Delivery Initiative (ASIDI), launched in 2011, has replaced only approximately 1,700 of the original 3,158 schools built from inappropriate materials (mud, corrugated iron, asbestos). The remaining backlog of approximately 1,400 schools represents a R32 billion capital liability. DBE''s Infrastructure and Sanitation Delivery Grant (ISDG) provides R9 billion per year but disbursement is constrained by weak provincial project management capacity, planning backlogs in the SIP 13 pipeline, and contractor non-performance. The programme must also address sanitation (an estimated 3,000 schools still using pit latrines) and electricity connections (1,200 schools off-grid). Accelerating delivery requires a structural reform of the ASIDI delivery model — moving from province-led procurement to a hybrid model combining DBE central programme management, CIDB-graded contractor panels, and SIP 13 project pipeline rationalisation.',
    '[{"step":1,"description":"DBE and PEDs conduct a full ASIDI backlog audit: verify remaining inappropriate structure schools by province; prioritise the 400 highest-risk schools (structural safety, pit latrines, off-grid) for immediate action; publish the audit as the ASIDI National Infrastructure Backlog Report 2025","timeline":"Q1–Q2 2025","responsible_party":"DBE Infrastructure Branch / ASIDI Programme Unit / PEDs"},{"step":2,"description":"Reform ASIDI delivery model: DBE establishes a central ASIDI Project Management Unit with 50 dedicated project managers; implement a CIDB Grade 6+ contractor panel to replace individual PED procurement — this alone is projected to reduce procurement time from 18 months to 6 months per project; introduce performance bonds for all ASIDI contractors","timeline":"Q2–Q3 2025","responsible_party":"DBE / CIDB / National Treasury / PEDs"},{"step":3,"description":"SIP 13 pipeline rationalisation: PICC and DBE review the Schools Infrastructure Project (SIP 13) pipeline; cancel stalled projects (>24 months with no progress); re-tender using the new central contractor panel; prioritise highest-impact schools in rural Eastern Cape, Limpopo, and KwaZulu-Natal","timeline":"Q2 2025–Q2 2026","responsible_party":"DBE / PICC / Presidential Infrastructure Coordinating Commission"},{"step":4,"description":"Emergency sanitation programme: replace all remaining pit latrines in schools within 3 years; use the ISDG sanitation sub-allocation (R2 billion/year); implement DBE''s Safe Sanitation Programme protocols to prevent collapses; report monthly to DBE Director-General on progress","timeline":"2025–2027","responsible_party":"DBE / PEDs / DWS"},{"step":5,"description":"Off-grid electrification programme: DBE partners with DMRE and Eskom to connect remaining 1,200 off-grid schools; where grid connection is cost-prohibitive (>R500,000/school), deploy solar-plus-storage systems through a DBE Solar Schools Programme using ISDG allocation","timeline":"2025–2027","responsible_party":"DBE / Eskom / DMRE / PEDs"},{"step":6,"description":"Annual parliamentary reporting: DBE tables an ASIDI Progress Report before the Portfolio Committee on Basic Education each year covering schools replaced, sanitation facilities completed, electrification connections, ISDG disbursement rate, and contractor performance ratings","timeline":"Annual (Q3 each year)","responsible_party":"DBE / Auditor-General of South Africa"}]',
    '2025–2030 to complete remaining ASIDI backlog; sanitation and electrification by 2027',
    'R32 billion total capital cost for remaining inappropriate structure replacement (R6–7 billion/year for five years); current ISDG funding of R9 billion/year covers this if disbursement efficiency is improved; sanitation and electrification estimated additional R5 billion; total programme R35–38 billion over five years, substantially within existing ISDG envelope if spend rate is accelerated',
    'No new primary legislation required. DBE''s Norms and Standards for School Infrastructure (2013) provide the legal basis. CIDB Act amendments may be needed to establish the DBE contractor panel mechanism. ISDG is a conditional grant under DORA — sub-allocations can be adjusted administratively.',
    'ISDG is a conditional grant adjusted annually through DORA schedules — budget committee process. CIDB contractor panel mechanism operates under existing CIDB Act powers. The central Project Management Unit is an administrative restructuring within DBE. No parliamentary legislation required for the delivery model reform.',
    'The DA-led Western Cape and ANC-led provinces agree on the need to eliminate mud schools — this is one of the least politically contested infrastructure commitments in education. The constraint is implementation capacity and contractor performance, not political will. DBE has faced sustained civil society pressure (Equal Education''s Limpopo school conditions litigation) and court orders compelling progress, which creates accountability.',
    'Rwanda''s Girinka school construction programme used a central government project management unit with standardised designs and pre-qualified contractors to build 3,000 schools in five years at 30% below provincial procurement costs — exactly the model ASIDI needs. Brazil''s PAR (Plano de Ações Articuladas) infrastructure programme used federal-municipal co-financing with central technical supervision to accelerate school construction, a useful model for DBE-PED co-management. India''s Sarva Shiksha Abhiyan (2001–2010) demonstrates both the potential and pitfalls of a large-scale school infrastructure programme — procurement fraud and quality failures when provincial capacity was insufficient.'
);

-- ── ID 91: National School Nutrition Programme Procurement Reform ─────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    91,
    'The National School Nutrition Programme (NSNP) feeds 9 million learners in 21,000 schools using approximately R8 billion per year, making it one of the largest public procurement programmes in South Africa. Procurement is currently delegated to nine provincial education departments, creating fragmented, corruption-prone procurement systems. The SIU has conducted investigations in the Eastern Cape and Limpopo revealing systemic fraud, inflated pricing, and ghost supplier payments worth hundreds of millions of rands annually. Centralising procurement through National Treasury''s State Information Technology Agency (SITA) transversal contracts and a reformed NSNP supplier framework — while maintaining province-specific menu and delivery logistics — is estimated to save R1–2 billion per year. The reform must be implemented carefully to avoid disrupting daily food delivery to vulnerable learners.',
    '[{"step":1,"description":"National Treasury and DBE commission a joint NSNP procurement audit: compare per-meal costs across all nine provinces; identify provinces with the highest cost overruns and SIU-flagged suppliers; establish a baseline NSNP Cost Per Meal Index for public accountability","timeline":"Q1–Q2 2025","responsible_party":"National Treasury / DBE / SIU"},{"step":2,"description":"Design centralised NSNP procurement framework: National Treasury establishes a NSNP Transversal Contract (RT designation) covering food commodity categories (maize meal, legumes, vegetables, cooking oil); conduct competitive tender with CIPC-verified, tax-compliant suppliers; allow provincial flexibility on menu composition within the framework","timeline":"Q2–Q4 2025","responsible_party":"National Treasury / SITA / DBE"},{"step":3,"description":"Provincial transition management: DBE and PEDs develop a 12-month transition plan from existing provincial contracts to the new transversal framework; ensure continuity of delivery — no school may go without feeding for more than three consecutive days during transition; maintain province-specific SMMEs as last-mile delivery contractors","timeline":"Q3 2025–Q2 2026","responsible_party":"DBE / PEDs / National Treasury"},{"step":4,"description":"NSNP digital management system: SITA deploys a national NSNP Learner Tracking and Procurement System integrating daily school attendance data, meal delivery confirmation (photo evidence), supplier payment records, and nutritional composition data; replace the current manual school-level record system","timeline":"Q2–Q4 2026","responsible_party":"SITA / DBE / PEDs"},{"step":5,"description":"SMME and community supplier integration: DBE''s NSNP guidelines reserve 30% of delivery sub-contracts for qualifying SMMEs and cooperatives within 50 km of schools; NSNP Project Management Units in each province manage SMME onboarding and compliance support","timeline":"2026 onwards","responsible_party":"DBE / PEDs / DSBD"},{"step":6,"description":"Independent nutritional audit and SIU outcome tracking: SAMRC commissions annual nutritional assessment of NSNP meals in a sample of 500 schools; SIU continues investigation of implicated suppliers and reports outcomes to National Treasury; DBE blacklists non-compliant suppliers from transversal contract","timeline":"Annual from 2026","responsible_party":"SAMRC / SIU / DBE / National Treasury"},{"step":7,"description":"Parliamentary accountability report: DBE tables an annual NSNP Report before the Portfolio Committee on Basic Education covering total spend, cost per meal by province, number of learners fed, nutritional compliance, SIU referrals, and projected savings from centralised procurement","timeline":"Annual (Q2 each year)","responsible_party":"DBE / National Treasury"}]',
    '2025–2026 for procurement framework; 2026–2027 for full transversal contract implementation; savings realised from 2026',
    'Centralised procurement implementation costs: R50–100 million (SITA system development, transition management); projected annual savings: R1–2 billion through competitive pricing and reduced fraud; net positive fiscal impact within 12 months of full implementation',
    'No new primary legislation required. National Treasury may issue a NSNP Transversal Contract under existing PFMA and SCM regulations. DBE''s NSNP Conditional Grant framework can be revised administratively to require provincial alignment with the transversal contract. PFMA regulations on deviation from transversal contracts would need tightening to prevent provinces bypassing the central system.',
    'National Treasury issues transversal contracts under PFMA Regulation 16A6.3 and SCM Practice Notes — no parliamentary legislation required. DBE adjusts NSNP Conditional Grant conditions through the annual DORA schedules. Any legislative change to mandate transversal contract use (overriding provincial procurement autonomy) would require amendment to the PFMA or a Cabinet instruction under section 216 of the Constitution.',
    'The SIU investigations create strong accountability pressure for reform — the existing system''s dysfunction is publicly documented. National Treasury has supported centralisation in principle. The main political risk is provincial resistance: PEDs that benefit from fragmented procurement (patronage networks and politically connected suppliers) will resist centralisation. Business (grocery retail, agribusiness) and civil society (Equal Education) support the reform. SADTU is neutral — the NSNP employs school-based food handlers who are not union members.',
    'Brazil''s PNAE (Programa Nacional de Alimentação Escolar) uses centralised federal procurement standards with mandatory local food purchase requirements (30% from family farmers), feeding 40 million students daily — the global benchmark for school feeding at scale. India''s Mid-Day Meal Scheme (now PM POSHAN) shifted from state-fragmented to centrally standardised menus and monitoring, reducing cost variance across states by 25% within three years. Ghana''s School Feeding Programme uses district-level procurement with centralised price benchmarks, preventing the worst overpricing while maintaining local procurement flexibility — a model for South Africa''s SMME integration requirement.'
);

-- ── ID 92: Mother-Tongue Based Multilingual Education Scale-up ───────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    92,
    'South Africa''s Language in Education Policy (1997) endorses mother-tongue-based multilingual education (MTB-MLE), but in practice most schools switch to English instruction from Grade 1 due to resource constraints, teacher capacity gaps, and parental preference for English as a perceived gateway to economic opportunity. Research consistently shows that children who learn to read in their home language acquire literacy faster and develop stronger cognitive foundations for learning additional languages. DBE''s current CAPS framework allows home language instruction through Grade 3 (bridging model) but implementation is inconsistent: textbooks in African languages are often unavailable, and few teachers are trained to teach in formal register in their home language. A systematic scale-up of isiZulu, isiXhosa, Sesotho, Sepedi, and Setswana medium instruction through Grade 6 — with a structured transition to English from Grade 4 — requires a ten-year investment in curriculum materials, teacher training, and community engagement.',
    '[{"step":1,"description":"DBE commissions a national Language in Education Landscape Survey: province-by-province mapping of actual Language of Learning and Teaching (LoLT) from Grade 1 onward, identifying the gap between policy (home language through Grade 3) and practice (English from Grade 1 in many schools); publish findings publicly","timeline":"Q1–Q2 2025","responsible_party":"DBE / PAN-SALB / Universities"},{"step":2,"description":"Develop African Language Medium CAPS curriculum materials for Grades 1–6 in the five most widely spoken African languages (isiZulu, isiXhosa, Sesotho, Sepedi, Setswana): commission complete textbook sets, teachers'' guides, and supplementary readers; use the same structured literacy phonics framework as the National Literacy Programme (ID 88)","timeline":"2025–2027","responsible_party":"DBE Curriculum Branch / PAN-SALB / Publishers"},{"step":3,"description":"Teacher language medium training programme: DHET accredits an Advanced Diploma in African Language Medium Teaching (Grades 1–6) through universities with strong African language departments (UNIZULU, UKZN, UL, UFS, NWU); target 10,000 teachers completing the qualification by 2030","timeline":"2025–2030","responsible_party":"DHET / Universities / SACE"},{"step":4,"description":"MTB-MLE pilot programme: DBE selects 500 schools per province (4,500 total) for structured MTB-MLE implementation through Grade 6 with dedicated monitoring; provide pilot schools with complete curriculum materials, trained teachers, and community liaison officers; evaluate outcomes against matched comparison schools","timeline":"2026–2028","responsible_party":"DBE / PEDs / HSRC"},{"step":5,"description":"Community and parent engagement campaign: DBE and provincial departments conduct a national campaign countering the perception that African language medium instruction limits children''s English acquisition; use PIRLS 2021 data and MTB-MLE research evidence; engage school governing bodies, traditional councils, and faith communities","timeline":"2025–2026 (ongoing)","responsible_party":"DBE / PAN-SALB / SABC Education"},{"step":6,"description":"PAN-SALB corpus development: Pan South African Language Board accelerates the development of standardised academic vocabulary in African languages for Grades 1–9 subject areas; prioritise mathematics and natural sciences terminology in all five target languages","timeline":"2025–2028","responsible_party":"PAN-SALB / DHET / Universities"},{"step":7,"description":"National MTB-MLE scale-up decision: based on pilot outcomes, DBE tables a Cabinet memorandum by end-2028 recommending whether to mandate MTB-MLE through Grade 6 nationally; if adopted, PEDs implement through revised Language Policy guidelines with a five-year transition period","timeline":"Q4 2028","responsible_party":"DBE / Cabinet Economic Cluster"}]',
    '2025–2030 for pilot and evidence phase; national mandate decision by end-2028; full scale-up 2029–2035 if adopted',
    'Curriculum materials development: R2 billion (textbooks in 5 languages for Grades 1–6); teacher training: R1.5 billion (10,000 Advanced Diplomas); pilot programme management: R500 million; PAN-SALB corpus development: R200 million; total R4.2 billion over ten years',
    'No new primary legislation required for the pilot phase — DBE can gazette revised CAPS Language of Learning and Teaching guidelines under existing statutory powers. A national mandate for MTB-MLE through Grade 6 may require amendment to the Schools Act or a new Language in Education Act, particularly given the constitutional protection of the right to receive education in the language of one''s choice (section 29(2)).',
    'Revised CAPS guidelines are ministerial administrative decisions under the Schools Act. The Community of Practice pilot is a DBE programme decision. A mandatory national MTB-MLE policy would require careful constitutional legal opinion — section 29(2) protects parental language choice, so any mandate would need to be structured as a strong default with opt-out provisions, not an absolute requirement. This would require at minimum a Cabinet-approved policy directive and potentially a Schools Act amendment.',
    'The reform is constitutionally and linguistically desirable but politically complex. ANC policy supports multilingualism but the party''s own cadres have historically enrolled children in English-medium schools. DA opposes any mandate that limits parental choice. EFF strongly supports African language promotion. SADTU supports the teacher development component. The critical variable is parental perception — community engagement is not optional, it is the primary implementation challenge.',
    'Papua New Guinea''s Elementary Education Policy has used vernacular language instruction for Grades 1–3 since 1993, with studies showing improved literacy outcomes relative to English-only schools. The Philippines'' Mother Tongue Based Multilingual Education Policy (DepEd Order 74, 2009) introduced MTB-MLE from Grade 1 in 12 regional languages with measurable improvements in Grade 3 numeracy and literacy. Ethiopia''s federal languages policy — instruction in regional languages through Grade 8 with English as a subject — offers a large-scale African comparator, including evidence on the role of teacher training in implementation quality.'
);

-- ── ID 93: Learner Transport Policy: Funded National Programme ───────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    93,
    'Between 5 and 7 million South African learners travel more than 5 kilometres to their nearest school without access to formal transport. In rural provinces — the Eastern Cape, Limpopo, and KwaZulu-Natal — learners walk dangerous distances, increasing absenteeism, dropout rates, and vulnerability to gender-based violence. The Learner Transport Policy (2015) assigns national and provincial co-responsibility for learner transport but provides no dedicated national grant. Current provincial spending on learner transport is estimated at R3–4 billion per year — roughly 20–25% of the R15 billion estimated need. DBE, in consultation with DoT and National Treasury, must design and fund a National Learner Transport Grant targeted at quintile 1–3 learners in rural and semi-urban areas, with standardised safety requirements and a contracted operator model.',
    '[{"step":1,"description":"DBE and DoT commission a National Learner Transport Needs Assessment: province-by-province mapping of learners travelling >5 km without transport; cost modelling for a universal rural transport programme using GPS school catchment data; publish findings as the basis for a National Learner Transport Grant business case","timeline":"Q1–Q2 2025","responsible_party":"DBE / Department of Transport / Statistics South Africa"},{"step":2,"description":"Design the National Learner Transport Grant: DBE and National Treasury structure a conditional grant covering quintile 1–3 learners in rural and peri-urban areas travelling >5 km; establish a per-learner subsidy rate (estimated R8,000–12,000/learner/year depending on terrain); incorporate safety standards (vehicle roadworthiness, driver vetting, seatbelts) into grant conditions","timeline":"Q2–Q3 2025 (for 2026/27 MTEF inclusion)","responsible_party":"DBE / National Treasury / DoT"},{"step":3,"description":"Operator procurement framework: DoT and provincial DoTs develop a standardised learner transport operator procurement framework (contract duration 3 years, performance penalties for non-delivery); use existing public transport operator licensing structures; prioritise locally-registered SMMEs and cooperatives for short-haul routes","timeline":"Q3–Q4 2025","responsible_party":"Department of Transport / Provincial DoTs / National Treasury"},{"step":4,"description":"Phased rollout: year 1 (2026) covers the 500,000 most vulnerable learners in the three highest-need provinces (Eastern Cape, Limpopo, KwaZulu-Natal); years 2–4 scale to all quintile 1–3 rural learners nationally; target 2 million learners covered by 2028","timeline":"2026–2028 phased rollout","responsible_party":"DBE / PEDs / Provincial DoTs"},{"step":5,"description":"Safety compliance enforcement: DBE and DoT establish a joint Learner Transport Safety Inspectorate; all contracted vehicles undergo annual roadworthiness certification; driver background checks conducted through the Criminal Record Centre; schools report transport incidents through a central DBE incident reporting system","timeline":"Ongoing from 2026","responsible_party":"DBE / DoT / SAPS"},{"step":6,"description":"Monitoring and evaluation: DBE tracks learner transport coverage rates, absenteeism data for transport beneficiaries vs. non-beneficiaries, gender-based violence incidents on transport routes, and operator contract compliance; publish annual Learner Transport Report","timeline":"Annual from 2027","responsible_party":"DBE / DoT / HSRC"}]',
    '2025–2026 for grant design and MTEF inclusion; 2026–2030 for phased rollout to 2 million learners',
    'R5 billion/year for 500,000 learners at R10,000/learner average cost in year 1, scaling to R15 billion/year for full programme coverage of approximately 1.5 million priority rural learners; current provincial spending of R3–4 billion/year provides a partial base; incremental national grant required: R8–10 billion/year at full scale',
    'No new primary legislation required. A National Learner Transport Grant is established through the Division of Revenue Act as a conditional grant — annual parliamentary budget legislation. DoT''s existing National Land Transport Act (2009) provides the legal framework for operator licensing. The 2015 Learner Transport Policy has existing legal standing — implementation requires only funding and inter-departmental coordination protocols.',
    'The grant is created through the annual DORA as a conditional grant — this is budget legislation that requires parliamentary passage but is non-controversial in process. The substantive policy decision (to fund the grant) requires Cabinet approval and MTEF budget commitment. DoT regulatory instruments (operator licences, roadworthiness certificates) operate under the National Land Transport Act without new legislation.',
    'All parties rhetorically support learner transport — the challenge is fiscal prioritisation against competing demands. National Treasury has historically resisted a new national grant, preferring provincial flexibility. However, the GBV and dropout evidence for unsafe school journeys is a compelling accountability argument. DA-governed Western Cape already operates a relatively well-funded provincial learner transport system and would support a national model that maintains provincial management flexibility. SADTU is neutral. Rural civic organisations strongly advocate for the programme.',
    'Brazil''s Caminho da Escola programme provides free school buses to rural municipalities based on federal per-student grants, covering 1.2 million students and reducing dropout in beneficiary schools by 18% — the closest international comparator. India''s school transport scheme under the National Rural Education Mission uses state-subsidised transport for girls travelling >1 km to secondary schools in 16 states, with documented impact on female secondary enrolment. Rwanda''s universal school feeding and transport programme demonstrates that even low-income countries can achieve near-universal access through dedicated national grants with strong monitoring.'
);

-- ── ID 94: Inclusive Education: Special Needs Schools and Full-Service Schools ────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    94,
    'Education White Paper 6 (2001) committed South Africa to an inclusive education system in which all learners, including those with disabilities, are accommodated in mainstream schools with appropriate support. Twenty-four years later, implementation is critically incomplete: only 465 full-service schools (mainstream schools adapted for learners with disabilities) exist against an estimated need for 22,000+ public schools. Approximately 300,000 learners with disabilities are enrolled in mainstream schools without any formal support, accommodation, or trained specialist teachers. A further 90,000 learners are in 454 special schools — a resource-intensive system that, properly resourced, serves learners with severe disabilities but cannot absorb the full spectrum of learners currently without support. The NSC Ministerial Task Team (2022) estimated R9 billion is needed over five years to bridge the full-service school gap. This programme operationalises a phased inclusive education strategy: converting 2,000 mainstream schools to full-service status by 2030 and significantly expanding specialist support capacity.',
    '[{"step":1,"description":"DBE completes the Inclusive Education Audit: province-by-province census of learners with disabilities in mainstream schools without support; identify which schools have the highest concentration of unsupported learners; map the 500 priority schools for first-phase full-service conversion","timeline":"Q1–Q2 2025","responsible_party":"DBE Inclusive Education Directorate / PEDs"},{"step":2,"description":"Full-service school conversion programme: DBE and PEDs convert 200 priority schools to full-service status per year from 2026; full-service conversion includes physical accessibility upgrades (ramps, accessible toilets), braille and assistive technology resources, appointment of at least one specialised support educator (SSE) per school, and enrolment of the school in the district-based support team system","timeline":"2026–2030 (200 schools/year)","responsible_party":"DBE / PEDs / ASIDI"},{"step":3,"description":"Specialised Support Educator (SSE) pipeline: DHET accredits a postgraduate Diploma in Inclusive Education and Specialised Support through universities and TVET colleges; SACE registers SSE as a specialist category; DBE funds 1,000 SSE bursaries/year through DHET''s Funza Lushaka pipeline; target 10,000 qualified SSEs by 2030","timeline":"2025–2030","responsible_party":"DHET / SACE / DBE"},{"step":4,"description":"District-Based Support Teams (DBSTs) strengthening: each of the 75 education districts must have a functional DBST with a psychologist, social worker, therapist, and learning support specialist; DBE and DPSA create the necessary post establishment; audit current DBST vacancies and fill within 18 months","timeline":"Q2 2025–Q4 2026","responsible_party":"DBE / DPSA / PEDs"},{"step":5,"description":"Assistive technology programme: DBE establishes a national assistive technology procurement framework (braille machines, hearing loop systems, communication devices, wheelchairs) through a National Treasury transversal contract; distribute to all full-service schools on conversion; create district AT maintenance and repair hubs","timeline":"2026–2028","responsible_party":"DBE / National Treasury / SITA"},{"step":6,"description":"Special school optimisation: DBE reviews the 454 special schools to ensure they serve learners with severe and profound disabilities who genuinely require specialised settings; redirect capacity freed by inclusive education placement to serve the highest-need learners; improve per-learner funding for special schools from current R15,000 to R35,000/year","timeline":"2025–2028","responsible_party":"DBE / National Treasury"},{"step":7,"description":"Annual Inclusive Education Progress Report: DBE tables an annual report to Parliament covering number of full-service schools, SSE appointments, DBST vacancies, assistive technology distribution, and learner outcomes for disabled learners in mainstream vs. special school settings","timeline":"Annual from Q3 2025","responsible_party":"DBE Inclusive Education Directorate / Auditor-General"}]',
    '2025–2030 for 1,000 full-service schools; 2030–2035 for 2,000 full-service schools; SSE pipeline target of 10,000 qualified staff by 2030',
    'R9 billion over five years as estimated by the NSC Ministerial Task Team: physical conversions (R3 billion), SSE bursaries (R2 billion), DBST staff (R2 billion), assistive technology (R1 billion), special school funding uplift (R1 billion); special school per-learner subsidy increase: R180 million/year additional',
    'No new primary legislation required — Education White Paper 6 provides policy framework; DBE can implement within existing Schools Act powers. Appointment of SSEs and DBST specialists requires DPSA post establishment approval and DPSA Determination on the remuneration of SSEs. SACE Act may require amendment for SSE specialist category registration. The Convention on the Rights of Persons with Disabilities (CRPD), ratified by South Africa in 2007, creates a binding international obligation for inclusive education.',
    'DPSA post creation requires consultation with National Treasury on the fiscal implications and MPAT compliance. The SSE category registration requires SACE Council resolution. Physical conversion funding flows through the ISDG as a conditional grant sub-allocation — DORA amendment required. No new primary legislation required but the cumulative administrative decisions require Cabinet Economic Cluster coordination.',
    'This is one of the most politically uncontested areas of education policy — all parties support inclusion and disability rights in principle. The CRPD ratification creates an international obligation. NGOs (Deaf SA, SANCB, DPO Forum) provide sustained advocacy. The main constraint is fiscal: R9 billion over five years competes with infrastructure and ECD commitments. National Treasury has historically underfunded inclusive education. The Parliamentary Portfolio Committee on Women, Youth and Persons with Disabilities provides additional accountability pressure.',
    'Canada''s province-by-province inclusive education implementation (Ontario, British Columbia) demonstrates that full-service school conversion is achievable at scale with adequate specialist teacher supply and district support teams — direct lessons for DBE''s DBST model. Portugal''s inclusive education reform (1991–2018) eliminated segregated special schools for most learners with disabilities and integrated them into mainstream schools with Resource Centres, achieving 95% inclusion by 2018. The CRPD General Comment No. 4 (2016) provides the UN''s authoritative framework for implementing inclusive education at national level.'
);

-- ── ID 95: Rural School Consolidation Policy ─────────────────────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    95,
    'South Africa has approximately 2,700 micro-schools with fewer than 100 learners, concentrated in rural Eastern Cape, Limpopo, KwaZulu-Natal, and North West. These schools consume disproportionate resources — each requires a principal, administrative function, and basic infrastructure — but cannot provide specialist teachers, full curriculum coverage, or extra-curricular activities. DBE''s Rural School Consolidation Strategy (2019) recommends closing 2,000 micro-schools over ten years and replacing them with well-resourced boarding schools and learner transport. Rural community resistance — rooted in fears about child safety, travel distances, cultural identity, and loss of community institutions — is the primary implementation barrier. The policy requires a combination of community consultation, credible boarding school infrastructure investment, learner transport provision, and transparent criteria for consolidation to overcome legitimate community concerns.',
    '[{"step":1,"description":"DBE publishes a Rural Micro-School Consolidation Criteria Framework: transparent criteria for identifying schools eligible for consolidation (fewer than 100 learners, within 30 km of a viable receiving school, no unique cultural or linguistic characteristics warranting preservation); conduct a national mapping exercise identifying all 2,700 micro-schools against these criteria; publish the list publicly","timeline":"Q1–Q2 2025","responsible_party":"DBE / PEDs / Statistics South Africa"},{"step":2,"description":"Community consultation protocol: DBE mandates a minimum 12-month community consultation process before any school closure can proceed; consultation must include local school governing bodies, traditional councils, ward councillors, and parent associations; outcomes documented and published; a formal objection process with DBE review provides procedural fairness","timeline":"Ongoing — preceding any consolidation","responsible_party":"DBE / PEDs / Local Government"},{"step":3,"description":"Boarding school investment programme: DBE and PEDs identify 300 receiving schools for upgrade to full boarding school status; ASIDI and ISDG fund dormitory construction, kitchen facilities, and security upgrades; target one quality boarding school per 50 km radius in consolidation areas; prioritise secondary schools to anchor the consolidation model","timeline":"2025–2029","responsible_party":"DBE / ASIDI / PEDs"},{"step":4,"description":"Learner transport package: micro-school consolidation is conditional on learner transport being in place before closure; DBE guarantees transport for all learners displaced by consolidation through the National Learner Transport Grant (ID 93); transport contracts are signed before consolidation is confirmed","timeline":"Concurrent with consolidation","responsible_party":"DBE / DoT / PEDs"},{"step":5,"description":"Phased consolidation targets: DBE and PEDs target 200 micro-school consolidations per year from 2026, prioritising schools where community consultation is complete and receiving school capacity is confirmed; staff redeployment plans developed for each closure to avoid retrenchments (teachers transferred to receiving schools or district specialist roles)","timeline":"2026–2031 (200/year for five years)","responsible_party":"DBE / PEDs / DPSA"},{"step":6,"description":"Community transition support: DBE establishes a Rural Community Education Trust to support communities affected by school closures — funding community learning centres, adult education programmes, and sports facilities in areas where the school building is repurposed; prevents the perception that consolidation abandons rural communities","timeline":"2026–2030","responsible_party":"DBE / DSAC / Local Government"},{"step":7,"description":"Annual consolidation review: DBE publishes an annual Rural School Consolidation Report covering consultations completed, schools closed, learners transported, boarding school upgrades, staff redeployments, and learner outcome comparisons between consolidated and micro-school cohorts; table before Portfolio Committee","timeline":"Annual from Q3 2026","responsible_party":"DBE / Auditor-General of South Africa"}]',
    '2025–2026 for framework and community consultation protocols; 2026–2031 for phased consolidation of 1,000 micro-schools; full 2,000 school programme by 2035',
    'Boarding school upgrades: R6 billion (300 schools at R20 million average); learner transport (already costed under ID 93); community transition support: R500 million; staff redeployment costs: R200 million; total direct consolidation programme cost: approximately R7 billion over ten years, offset by savings of R2–3 billion/year in operating costs of closed micro-schools',
    'No new primary legislation required. DBE can close schools under section 33 of the Schools Act, which requires a public participation process. The 12-month community consultation protocol is a DBE policy requirement, not a statutory one, but provides the procedural fairness needed to withstand legal challenge. Staff redeployment (rather than retrenchment) must comply with the Labour Relations Act and the Employment of Educators Act.',
    'School closure notices are published by the MEC under section 33 of the Schools Act after public participation. DBE''s consolidation criteria and timeline are policy decisions implemented through administrative gazette notices. Staff redeployment must follow LRA and EEA procedures — no new legislation required but strict procedural compliance is essential. Boarding school ASIDI funding is a conditional grant adjustment under DORA.',
    'This is the most politically sensitive education reform on this list. Rural communities regard local schools as community anchors — losing a school is perceived as institutional abandonment. Traditional leaders oppose closures in their jurisdictions. ANC branches in rural provinces have blocked consolidation in the past. DBE must invest as heavily in community engagement and boarding school quality as in the consolidation process itself. The prerequisite conditions (transport guarantee, boarding school investment, community trust fund) are not optional extras — they are the political price of implementation.',
    'Ireland''s rural school consolidation programme (2011–2018) successfully closed 1,200 small rural schools using a transparent criteria framework, community transition funds, and investment in receiving schools; the process took eight years and required sustained political commitment at ministerial level. Scotland''s Rural School Review (2009) established a consultative process that prevented premature closures while achieving targeted consolidation — a model for DBE''s community consultation protocol. China''s Cunshu Chengzhen rural school merger programme (2001–2012) relocated 400,000 rural schools into boarding schools, improving educational outcomes but causing serious social disruption — a cautionary precedent highlighting the necessity of adequate boarding school quality and transport.'
);

COMMIT;
